class ApiLoggingInterceptor(
    private val tag: String = "API",
    private val logHeaders: Boolean = true,
    private val logBody: Boolean = true,
    private val logResponseBody: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val requestId = CorrelationIds.newId("http")
        val request = chain.request()
        val startedNs = System.nanoTime()

        if (AppLogger.enabled) {
            val url = request.url.toString()
            val method = request.method
            val headers = if (logHeaders) AppLogger.redactHeaders(request.headers) else Headers.Builder().build()
            val headerString = if (logHeaders) headersToString(headers) else "(headers omitted)"
            val bodyString = if (logBody) requestBodyToStringSafe(request) else "(body omitted)"
            Timber.tag(tag).v(
                "[$requestId] --> %s %s\n%s\n%s",
                method,
                url,
                headerString,
                bodyString
            )
        }

        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            AppLogger.exception(tag, t, "[$requestId] HTTP FAILED: ${request.method} ${request.url}")
            throw t
        }

        val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startedNs)

        if (!AppLogger.enabled) return response

        val code = response.code
        val message = response.message
        val headers = if (logHeaders) AppLogger.redactHeaders(response.headers) else Headers.Builder().build()
        val headerString = if (logHeaders) headersToString(headers) else "(headers omitted)"

        if (!logResponseBody) {
            Timber.tag(tag).v(
                "[$requestId] <-- %d %s (%dms) %s\n%s\n(body omitted)",
                code,
                message,
                tookMs,
                response.request.url,
                headerString
            )
            return response
        }

        val responseBody = response.body
        if (responseBody == null) {
            Timber.tag(tag).v(
                "[$requestId] <-- %d %s (%dms) %s\n%s\n(no body)",
                code,
                message,
                tookMs,
                response.request.url,
                headerString
            )
            return response
        }

        val contentType = responseBody.contentType()
        val bodyString = responseBodyToStringSafe(responseBody, contentType)
        Timber.tag(tag).v(
            "[$requestId] <-- %d %s (%dms) %s\n%s\n%s",
            code,
            message,
            tookMs,
            response.request.url,
            headerString,
            bodyString
        )

        val newBody = ResponseBody.create(contentType, responseBody.bytesSafe())
        return response.newBuilder().body(newBody).build()
    }

    private fun headersToString(headers: Headers): String {
        if (headers.size == 0) return "(no headers)"
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            sb.append(headers.name(i)).append(": ").append(headers.value(i)).append('\n')
        }
        return sb.toString().trimEnd()
    }

    private fun requestBodyToStringSafe(request: Request): String {
        val body = request.body ?: return "(no body)"
        val buffer = Buffer()
        return try {
            body.writeTo(buffer)
            val charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val raw = buffer.readString(charset)
            val redacted = AppLogger.redactText(raw)
            AppLogger.truncate(redacted)
        } catch (e: Throwable) {
            "(unable to read request body: ${e.javaClass.simpleName}: ${e.message})"
        }
    }

    private fun ResponseBody.bytesSafe(): ByteArray {
        return try {
            this.bytes()
        } catch (_: Throwable) {
            ByteArray(0)
        }
    }

    private fun responseBodyToStringSafe(body: ResponseBody, contentType: MediaType?): String {
        return try {
            val bytes = body.bytesSafe()
            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val raw = bytes.toString(charset)
            val redacted = AppLogger.redactText(raw)
            AppLogger.truncate(redacted)
        } catch (e: Throwable) {
            "(unable to read response body: ${e.javaClass.simpleName}: ${e.message})"
        }
    }
}

class ExceptionLoggingHandler(
    private val tag: String = "Uncaught"
) : Thread.UncaughtExceptionHandler {

    private val previous: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()

    fun install() {
        Thread.setDefaultUncaughtExceptionHandler(this)
    }

    override fun uncaughtException(t: Thread, e: Throwable) {
        try {
            AppLogger.exception(tag, e, "Uncaught exception on thread=${t.name}")
        } catch (_: Throwable) {
        } finally {
            previous?.uncaughtException(t, e)
        }
    }
}

